package com.chaobo.scm.supplier.interfaces.web;

import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.finance.SupplierFinanceLifecycleApplicationService;import com.chaobo.scm.supplier.infrastructure.security.CommandContextFactory;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;import java.math.BigDecimal;
@RestController @RequestMapping("/api/supplier/v1")public class SupplierFinanceLifecycleController {private final SupplierFinanceLifecycleApplicationService service;private final CommandContextFactory contexts;public SupplierFinanceLifecycleController(SupplierFinanceLifecycleApplicationService service,CommandContextFactory contexts){this.service=service;this.contexts=contexts;}@PostMapping("/reconciliations/{id}/resolve")public ApiResponse<Void> resolve(@PathVariable long id,@Valid @RequestBody Resolve b,HttpServletRequest r,Authentication a){service.resolveDifference(id,b.version(),b.confirmedAmount(),b.resolution(),contexts.create(r,a));return ok(r);}@PostMapping("/reconciliations/{id}/close")public ApiResponse<Void> close(@PathVariable long id,@Valid @RequestBody Version b,HttpServletRequest r,Authentication a){service.closeReconciliation(id,b.version(),contexts.create(r,a));return ok(r);}@PostMapping("/invoices/{id}/resubmit")public ApiResponse<Void> resubmit(@PathVariable long id,@Valid @RequestBody Invoice b,HttpServletRequest r,Authentication a){service.resubmitInvoice(id,b.version(),b.amountExcludingTax(),b.taxAmount(),b.taxRate(),b.attachmentUrl(),contexts.create(r,a));return ok(r);}@PostMapping("/invoices/{id}/close")public ApiResponse<Void> closeInvoice(@PathVariable long id,@Valid @RequestBody Version b,HttpServletRequest r,Authentication a){service.closeInvoice(id,b.version(),contexts.create(r,a));return ok(r);}private ApiResponse<Void> ok(HttpServletRequest r){return ApiResponse.success(null,r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}public record Version(@PositiveOrZero int version){}public record Resolve(@PositiveOrZero int version,@DecimalMin("0")BigDecimal confirmedAmount,@NotBlank String resolution){}public record Invoice(@PositiveOrZero int version,@DecimalMin("0")BigDecimal amountExcludingTax,@DecimalMin("0")BigDecimal taxAmount,@DecimalMin("0")BigDecimal taxRate,@NotBlank String attachmentUrl){}}
